module.render:
const color = args.color || 'var(--accent-color)';
const unit = args.unit || '';
const showValues = !(args.showvalues === false || args.showvalues === 'false');
const sort = (args.sort || 'none').toLowerCase();
const barH = (() => { const n = parseFloat(args.barheight); return Number.isFinite(n) && n > 0 ? n : 1.4; })();
const radius = (() => { const n = parseFloat(args.radius); return Number.isFinite(n) && n >= 0 ? n : 5; })();
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const rows = [];
sections.forEach((s) => {
  const m = String(s || '').trim().match(/^([\s\S]*?)[:|]\s*(-?[\d.]+)\s*$/);
  if (!m) return;
  rows.push({ label: m[1].trim(), value: parseFloat(m[2]) });
});
if (!rows.length) return `<div class="mdp-mod-barchart">(each section must be "Label: value")</div>`;
if (sort === 'desc') rows.sort((a, b) => b.value - a.value);
else if (sort === 'asc') rows.sort((a, b) => a.value - b.value);
let max = parseFloat(args.max) || 0;
if (!max) max = Math.max(...rows.map((r) => Math.abs(r.value)), 1);
let html = `\n\n<div class="mdp-mod-barchart" style="--bc-color:${color}; --bc-h:${barH}em; --bc-r:${radius}px;">`;
rows.forEach((r) => {
  const w = Math.max(0, Math.min(100, (r.value / max) * 100));
  html += `<div class="mdp-bc-row"><span class="mdp-bc-label">${esc(r.label)}</span>` +
    `<span class="mdp-bc-track"><span class="mdp-bc-bar" style="width:${w.toFixed(1)}%;"></span></span>` +
    (showValues ? `<span class="mdp-bc-val">${esc(String(r.value))}${esc(unit)}</span>` : '') +
    `</div>`;
});
html += `</div>\n\n`;
return html;
